@using sv_733a2dd2f8b840c9a03a0d5215e69fe5.Services

<li class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-name"># @Channel.Name</div>
    <div class="channel-description">@TruncatedDescription</div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</li>

@code {
    [Parameter, EditorRequired]
    public Channel Channel { get; set; } = default!;

    [Parameter]
    public bool IsActive { get; set; }

    [Parameter]
    public EventCallback<int> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;

    private async Task HandleClick() => await OnSelected.InvokeAsync(Channel.Id);
}

::deep .channel-item {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    transition: background-color 0.15s;
}

::deep .channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

::deep .channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
    font-weight: 600;
}

::deep .channel-name {
    flex: 1;
    font-size: 0.95rem;
    color: #e0e0e0;
}

::deep .channel-item.active .channel-name {
    color: #fff;
}

::deep .channel-description {
    width: 100%;
    font-size: 0.75rem;
    color: #999;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

::deep .unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

@using sv_733a2dd2f8b840c9a03a0d5215e69fe5.Services

<div class="message-input-area">
    <textarea @bind="Text" @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="send-btn" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter]
    public string Placeholder { get; set; } = "Type a message…";

    [Parameter]
    public string ButtonLabel { get; set; } = "Send";

    [Parameter]
    public EventCallback<string> OnSend { get; set; }

    private string Text { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var content = Text.Trim();
        Text = "";
        await OnSend.InvokeAsync(content);
    }
}

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #3a3a3a;
    background: #2b2b2b;
}

.message-input-area textarea {
    flex: 1;
    resize: none;
    border: 1px solid #444;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.9rem;
    background: #1e1e1e;
    color: #e0e0e0;
    font-family: inherit;
}

.message-input-area textarea:focus {
    outline: none;
    border-color: #5b9bd5;
}

.send-btn {
    align-self: flex-end;
    padding: 8px 20px;
    border: none;
    border-radius: 6px;
    background-color: #5b9bd5;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.15s;
}

.send-btn:hover:not(:disabled) {
    background-color: #4a8ac4;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_733a2dd2f8b840c9a03a0d5215e69fe5.Services

<div class="message-item" @onmouseenter="() => _showActions = true" @onmouseleave="() => _showActions = false">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions-row">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">💬 Reply</button>
            <div class="emoji-picker">
                @foreach (var emoji in _commonEmojis)
                {
                    <button class="emoji-btn" @onclick="() => OnReact.InvokeAsync((Message.Id, emoji))">@emoji</button>
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message Message { get; set; } = default!;

    [Parameter]
    public int ReplyCount { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;

    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👀"];

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: rgba(255, 255, 255, 0.03);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.9rem;
    color: #ccc;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #444;
    border-radius: 12px;
    background: #2a2a2a;
    color: #ddd;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #3a3a3a;
    border-color: #5b9bd5;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 0;
    border: none;
    background: none;
    color: #5b9bd5;
    font-size: 0.8rem;
    cursor: pointer;
    font-weight: 600;
}

.thread-link:hover {
