toolArgs.file_text:
.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: rgba(255, 255, 255, 0.03);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.timestamp {
    font-size: 0.75rem;
    color: #888;
}

.message-content {
    font-size: 0.9rem;
    color: #ccc;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #444;
    border-radius: 12px;
    background: #2a2a2a;
    color: #ddd;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #3a3a3a;
    border-color: #5b9bd5;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 0;
    border: none;
    background: none;
    color: #5b9bd5;
    font-size: 0.8rem;
    cursor: pointer;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 4px;
    right: 8px;
    display: flex;
    align-items: center;
    gap: 4px;
    background: #333;
    border: 1px solid #444;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.3);
}

.action-btn {
    padding: 4px 8px;
    border: none;
    background: none;
    color: #ccc;
    font-size: 0.8rem;
    cursor: pointer;
    border-radius: 4px;
}

.action-btn:hover {
    background: #444;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    border-left: 1px solid #555;
    padding-left: 4px;
    margin-left: 2px;
}

.emoji-btn {
    padding: 4px;
    border: none;
    background: none;
    font-size: 1rem;
    cursor: pointer;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background: #444;
}

