@page "/chat"
@using sv_733a2dd2f8b840c9a03a0d5215e69fe5.Services
@rendermode InteractiveServer
@inject IChatService ChatService
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="SelectChannelAsync" />
    </div>

    <div class="chat-main @(_threadOpen ? "" : "chat-main-wide")">
        <MessageArea Channel="_activeChannel"
                     Messages="_messages"
                     ThreadSummaries="_threadSummaries"
                     IsLoadingMore="_isLoadingMore"
                     OnLoadMore="LoadMoreMessagesAsync"
                     OnOpenThread="OpenThreadAsync"
                     OnReact="HandleReactionAsync"
                     OnSendMessage="SendMessageAsync" />
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReplyAsync"
                         OnReact="HandleReactionAsync" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = [];
    private int _activeChannelId;
    private Channel? _activeChannel;
    private bool _isLoadingMore;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0].Id);
        }
    }

    private async Task SelectChannelAsync(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.Find(c => c.Id == channelId);

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);

        // Update the channel's unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }

        // Close any open thread when switching channels
        CloseThread();
    }

    private async Task LoadMoreMessagesAsync()
    {
        if (_isLoadingMore || _activeChannel is null) return;

        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId, _messages.Count, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            BuildThreadSummaries();
        }

        _isLoadingMore = false;
    }

    private async Task SendMessageAsync(string content)
    {
        if (_activeChannel is null) return;

        var message = await ChatService.SendMessageAsync(_activeChannelId, content, null);
        _messages.Add(message);
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        _threadRootMessage = _messages.Find(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (_threadRootMessage is null || _activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update thread summary
        _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
            _threadRootMessage.Id,
            _threadReplies.Count,
            reply.SentAt
        );
    }

    private async Task HandleReactionAsync((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the reaction in the local message list
        UpdateReactionLocally(_messages, args.MessageId, args.Emoji);
        UpdateReactionLocally(_threadReplies, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionLocally(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FindIndex(r => r.Emoji == emoji);

        if (existing >= 0)
        {
            var r = reactions[existing];
            reactions[existing] = r with { Users = [..r.Users, "You"] };
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }

        messages[idx] = msg with { Reactions = reactions };
    }

    private void BuildThreadSummaries()
    {
        // Build thread summaries from messages that are replies
        var replies = _messages.Where(m => m.ReplyToId.HasValue).ToList();
        _threadSummaries = replies
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt))
            );
    }

    public ValueTask DisposeAsync() => ValueTask.CompletedTask;
}

.chat-layout {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    background: #1e1e1e;
    color: #e0e0e0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 300px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
}

.chat-main-wide {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

window.ChatScrollObserver = {
    _observer: null,
    _sentinel: null,

    init: function (scrollContainer, dotNetRef) {
        // Create a sentinel element at the top of the scroll container
        const sentinel = document.createElement('div');
        sentinel.style.height = '1px';
        scrollContainer.prepend(sentinel);
        this._sentinel = sentinel;

        this._observer = new IntersectionObserver(
            (entries) => {
                if (entries[0].isIntersecting) {
                    dotNetRef.invokeMethodAsync('OnScrolledToTop');
                }
            },
            {
                root: scrollContainer,
                threshold: 0.1
            }
        );

        this._observer.observe(sentinel);
    },

    dispose: function () {
        if (this._observer) {
            this._observer.disconnect();
            this._observer = null;
        }
        if (this._sentinel) {
            this._sentinel.remove();
            this._sentinel = null;
        }
    }
};

