export function initScrollObserver(scrollContainer, dotNetRef) {
    const sentinel = document.createElement('div');
    sentinel.style.height = '1px';
    sentinel.dataset.scrollSentinel = 'true';
    scrollContainer.prepend(sentinel);

    const observer = new IntersectionObserver(
        (entries) => {
            if (entries[0].isIntersecting) {
                dotNetRef.invokeMethodAsync('OnScrolledToTop');
            }
        },
        {
            root: scrollContainer,
            threshold: 0.1
        }
    );

    observer.observe(sentinel);
    scrollContainer._chatObserver = observer;
    scrollContainer._chatSentinel = sentinel;
}

export function disposeScrollObserver(scrollContainer) {
    if (scrollContainer?._chatObserver) {
        scrollContainer._chatObserver.disconnect();
        scrollContainer._chatObserver = null;
    }
    if (scrollContainer?._chatSentinel) {
        scrollContainer._chatSentinel.remove();
        scrollContainer._chatSentinel = null;
    }
}

