arguments.new_str:
@using sv_733a2dd2f8b840c9a03a0d5215e69fe5.Services
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-list" @ref="_scrollContainer">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ReplyCount="GetReplyCount(message.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Message> Messages { get; set; } = [];

    [Parameter]
    public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];

    [Parameter]
    public bool IsLoadingMore { get; set; }

    [Parameter]
    public EventCallback OnLoadMore { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference _scrollContainer;
    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<MessageList>? _dotNetRef;

    private int GetReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-733a2dd2f8b840c9a03a0d5215e69fe5/Components/Chat/MessageList.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _jsModule.InvokeVoidAsync("initScrollObserver", _scrollContainer, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await OnLoadMore.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            try
            {
                await _jsModule.InvokeVoidAsync("disposeScrollObserver", _scrollContainer);
                await _jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }
}

